class Solution:
    def removeNodesFromRightMostColumn(self, root: TreeNode) -> TreeNode:
        if not root:
            return None
        if not root.left and not root.right:
            return None
        queue = [root]
        while queue:
            level_size = len(queue)
            for _ in range(level_size):
                node = queue.pop(0)
                if node.left:
                    queue.append(node.left)
                if node.right:
                    queue.append(node.right)
            rightmost_node = queue[-1]
            if not rightmost_node.left and not rightmost_node.right:
                return self.removeNodesFromRightMostColumn(rightmost_node)
            rightmost_node.left = None
        return root
    def removeNodesFromRightMostColumnHelper(self, root: TreeNode) -> TreeNode:
        if not root:
            return None
        if not root.left and not root.right:
            return None
        root.right = self.removeNodesFromRightMostColumnHelper(root.right)
        return root

    def removeNodesFromRightMostColumnMain(self):
        root = TreeNode(1)
        root.left = TreeNode(2)
        root.right = TreeNode(3)
        root.left.left = TreeNode(4)
        root.right.right = TreeNode(5)
        root.left.left.right = TreeNode(6)
        root.right.right.right = TreeNode(7)

        result = self.removeNodesFromRightMostColumn(root)

        print('Result:', result.val)
        print('Expected:', 1)

        self.assertEqual(result.val, 1)

        result = self.removeNodesFromRightMostColumnHelper(root)

        print('Result:', result.val)
        print('Expected:', 1)

        self.assertEqual(result.val, 1)

    def removeNodesFromRightMostColumnTest(self):
        self.removeNodesFromRightMostColumnMain()


if __name__ == '__main__':
