#include <iostream>
#include <vector>
#include <queue>

using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    TreeNode* removeNodesFromRightMostColumn(TreeNode* root) {
        if (!root) return nullptr;
        if (root->left == nullptr && root->right == nullptr) return nullptr;
        queue<vector<TreeNode*>*> levels;
        levels.push_back({root});
        while (!levels.empty()) {
            vector<TreeNode*>* current_level = levels.front();
            levels.pop_front();
            for (int i = current_level->size() - 1; i >= 0; --i) {
                TreeNode* node = (*current_level)[i];
                if (!node->left && !node->right) {
                    return removeNodesFromRightMostColumn(node->right);
                }
                if (node->right) {
                    levels.push_back({&node->right});
                }
            }
        }
        return root;
    }
};

int main() {
    Solution solution;
    // Test case 1
    TreeNode* root = new TreeNode(1);
    root->left = new TreeNode(2);
    root->right = new TreeNode(3);
    root->left->left = new TreeNode(4);
    root->right->right = new TreeNode(5);
    root->left->left->right = new TreeNode(6);
    root->right->right->right = new TreeNode(7);

    TreeNode* result = solution.removeNodesFromRightMostColumn(root);

    // Print the result
    cout << ' Result: ' << result->val << endl;

    // Print the expected result
    cout << ' Expected: 1' << endl;

    // Check if the result is as expected
    assert(result->val == 1);

    // Test case 2
    root = new TreeNode(1);
    root->right = new TreeNode(2);
    root->right->right = new TreeNode(3);

    result = solution.removeNodesFromRightMostColumn(root);

    // Print the result
    cout << ' Result: ' << result->val << endl;

    // Print the expected result
    cout << ' Expected: 1' << endl;

    // Check if the result is as expected
    assert(result->val == 1);

    return 0;
}
